// // This module compares two 8-bit numbers and outputs 1 if the first number is less than or equal to the second number.
module comparator_8bit(
    input [7:0] a,
    input [7:0] b,
    output reg gt);

always @* begin
    if (a > b)
        gt = 1'b1;
    else
        gt = 1'b0;
end

endmodule
